arguments.new_str:
// EF Core 9 breaking change: Migrate() can no longer be called inside a
// user-initiated transaction. Each migration is now applied in its own
// transaction automatically, so wrapping it is unnecessary and will throw.
void ApplyMigrations(AppDbContext db)
{
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        db.Database.Migrate();
    });
}

